INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00813', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「古人欣賞奇磔虬勁的奇木奇石，大概是因為那奇磔虬勁中隱藏透露著生命奮鬥的痕跡吧！當那掙扎 求活的傷痛過去，那掙扎求活的姿態卻成了使人歌讚的對象。後人把玩、瀏覽、細細撫愛，那使人歌 讚的紋痕之美，何人還記得來自於心痛如絞的傷痛呢？」 根據上文，下列選項何者最符合作者的意思？', '["奇磔的木石，呈現大自然鬼斧神工的創造", "欣賞木石的紋痕，能激發人們歌讚的衝動", "人們喜愛把玩木石，是因其本身紋痕之美", "木石的奇磔虬勁，蘊含生命苦難奮鬥過程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00814', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「年過五十，雖然越來越貪生怕死，卻從未認真從事攸關延長壽命的任何活動，五穀依舊不分、四體 越發不勤。飯桌上，絕不煞風景地拒絕肥碩欲滴的蹄膀，平日喝咖啡像倒開水，電腦桌前一坐便是大 半天。乾眼症跟著五十肩，胃痛加上失眠，我都視之為天將降大任的考驗。啊！年過半百，其實已胸 無大志，一點也不想兼善天下，既沒有本事做大官，也不想聽國父的話去做大事，只偷偷祈求一點點 的榮華，一些些的富貴，少少的美貌和一位跑不掉的丈夫。」 根據上文，有關「年過五十」的敘述，何者錯誤？', '["對於自身的不足能夠自我調侃，一笑置之", "對於人生已無太大的奢求，真心所望的不過是最平凡的事", "腦袋不夠清楚，卻認真從事攸關延長壽命的活動，而且身體力行", "心情有些複雜，明明身體開始衰老，卻只能以「天將降大任」自嘲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00815', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「誰都不是一座島嶼，自成一體；每個人都是廣袤大陸的一部分。」下列選項，何者最接近上文旨意？', '["應追求自我卓越，開拓個人寬廣的人生", "學貴博通，不可閉門造車，須隨時精進", "人不是單獨存在的，不能自外於人群社會", "在團體中，多數人必須尊重少數人的意見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00816', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「當我四處行走之際，『我總有幾本書防身』。我讀著書本，有時候我循書中線索走進陌生城市的僻巷 酒店或黑暗城區餐廳，並不特別感到害怕，因為我知道我有『某位知識豐富的友人』與我相伴，我其 實並不孤單。每一本書的存在，就意味著一位『前行者』的存在。你並不是一位『冒險者』，你只是一 位『追隨者』。」 閱讀以上文字，下列敘述何者正確？', '["書本可以當作武器，對付壞人", "書本與旅行的關係，是冒險者與追隨者的關係", "作者旅行時帶著書，就像是知識豐富的友人相伴，所以不孤單", "作者走進黑暗城區餐廳之所以不害怕，因為這是朋友介紹的餐廳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00817', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '「網路上有一則發人深省的廣告，在一場馬拉松競賽上，一名選手突然對比賽產生了疑惑。他問：『大 家都說人生就像一場馬拉松。真是這樣的嗎？為什麼大家都朝向同一個方向、同一個目標呢？』『我 能不能退出這場比賽？我能不能選擇其他的方向？』畫面上，他看到有人不幸跌倒了，仍然勉強站起 來繼續向前，他的疑惑更深了，於是，他勇敢的率先跑出隊伍；其他人也看到了，紛紛起而響應，每 一個人都奔向自己的方向。」 關於上文，說明正確的選項為：', '["這名選手會突然產生疑惑，是因為開始認真自省落後的原因", "這名選手看到有人不幸跌倒卻還是勉強起身，不禁自慚形穢", "這名選手率先跑出隊伍，是想順著自己主動選擇的方向前進", "作者認為當大家都朝同個目標前進時，打破規則才能先抵達"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00818', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '關於公文擬稿時之注意事項，下列選項何者錯誤？', '["各種名稱如非習用有素，不宜省文縮寫", "文中引敘法令條文，宜抄錄全文以求慎重", "字跡力求清晰，不得潦草，如有添改，應於添改處蓋章", "擬稿須條理分明，其措詞以切實、誠懇、簡明扼要為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00819', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '承辦單位在完成上級機關交辦之公務事項後，欲向上級機關回覆，下列經辦語何者正確？', '["茲經", "嗣經", "復經", "遵經"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00820', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '下列公文稱謂用語，何者錯誤？', '["內政部對行政院長稱「鈞長」", "監察院行文審計部稱「貴部」", "勞工保險局對勞動部自稱「本局」", "僑務委員會行文教育部稱「鈞部」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00821', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '下列公文期望語用法，何者不恰當？', '["交通部函文給行政院，可用「請鑒察」", "警政署函文給矯正署，可用「請查照」", "臺北市敦化國小函文給臺北市教育局，可用「請照辦」", "高雄市永安漁會函文給行政院農業委員會，可用「請鑒核」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00822', 'judicial-57f41407', 'judicial-57f41407-moex-110-01c5eaab', 'sub-judicial-57f41407-05', NULL, 'single_choice', '各機關處理機密文書應注意事項，下列選項何者正確？', '["文書之收發處理，與各類文件混合登記時，登註資料應顯示機密等級", "文書用印時，監印人員憑主管簽署用印，得閱覽文件內容以防止錯誤", "核定之機密文書若屬於彙編性質者，應於文書首頁說明保密要求事項", "辦理機密文書簽擬稿若有誤繕印之廢紙，應由承辦人員即時妥善保管"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "1ce51c07af4a", "answer_pdf_sha1": "e33fceeebc66", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
